import{a as e}from"./chunk-B4MHUD6F.js";import"./chunk-IFGU66OU.js";var t={meta:e,sections:[{id:"overview",title:"Overview",blocks:[{type:"markdown",value:"A URL shortener turns a long URL into a short alias (e.g. `https://sho.rt/aZ9kQ`) that redirects to the original. Think TinyURL or Bitly. It is a classic interview problem because it is small enough to design fully yet touches **hashing, unique ID generation, caching, and read-heavy scaling**."},{type:"callout",variant:"info",title:"Core insight",body:"This is an overwhelmingly **read-heavy** system (redirects far outnumber creations) where the key design choice is *how to generate short, unique, collision-free keys*."}]},{id:"clarifying-questions",title:"Clarifying Questions",blocks:[{type:"markdown",value:"Spend the first 3\u20135 minutes narrowing scope before drawing anything. A URL shortener sounds trivial, but the answers here decide key length, whether you need a reverse-lookup index, and how hard caching/analytics have to work \u2014 interviewers are watching for this instinct, not just the final diagram."},{type:"table",caption:'Questions to ask, and reasonable assumptions if the interviewer says "you decide".',headers:["Question","Why it matters / sample assumption"],rows:[["What scale are we designing for (URLs created/day, redirects/day)?","Assume ~100M new URLs/month and a 100:1 read:write ratio \u2014 this alone justifies a cache and drives the key-length math."],["How long should short URLs remain valid \u2014 forever, or with expiration?","Assume most links never expire, but support an optional `expiresAt`; expired links free up storage and can even free up the key."],["Do we need custom/vanity aliases (e.g. `/promo2026`)?","Yes, as an optional feature \u2014 it changes the write path (must check availability) but not the core redirect path."],["Do we need click analytics (counts, geography, referrer)?","Basic click counts only, updated asynchronously off the hot redirect path \u2014 full analytics is a stated non-goal."],["Should the same long URL always map to the same short URL?","No \u2014 assume distinct requests can get distinct codes (simplifies the write path); mention a reverse-index as an optional dedup optimization."],["Do short codes need to be unguessable (security-sensitive links)?","Assume yes for anything user-generated \u2014 add randomness/shuffling on top of the key-generation scheme so codes are not sequentially enumerable."],["Is this single-region or globally distributed?","Start single-region for the core design; call out multi-region replication and a CDN edge cache as a scaling extension."]]},{type:"callout",variant:"tip",title:"Say your assumptions out loud",body:'Even when the interviewer says "you decide," state the assumption explicitly ("I will assume a 100:1 read:write ratio and no dedup on identical URLs") before moving on. It shows deliberate scoping rather than guessing, and gives the interviewer a chance to correct you early \u2014 much cheaper than redesigning later.'}]},{id:"functional-requirements",title:"Functional Requirements",blocks:[{type:"bestPractices",title:"Must-haves",practices:["Create a short URL from a long URL.","Redirect a short URL to the original (HTTP 301/302).","Optional custom alias (vanity links).","Optional expiration time.","Basic analytics (click counts)."]}]},{id:"non-functional-requirements",title:"Non-Functional Requirements",blocks:[{type:"prosCons",pros:["Very low redirect latency (it is on the critical path of someone's click).","High availability \u2014 a dead link service breaks every shared link.","Short, hard-to-guess keys."],cons:["Strong consistency not required for analytics.","Write volume is low relative to reads."]}]},{id:"capacity-estimation",title:"Capacity Estimation",blocks:[{type:"metrics",items:[{label:"New URLs / month",value:"100M",hint:"writes"},{label:"Read:Write ratio",value:"100:1",hint:"redirects dominate"},{label:"Reads / month",value:"10B",hint:"redirects"},{label:"Storage / 5 yrs",value:"~6 TB",hint:"6B rows \xD7 ~1KB"}]},{type:"markdown",value:"How long must the key be? With a Base62 alphabet `[A-Za-z0-9]`, an `n`-character key yields:"},{type:"math",display:!0,tex:"62^{7} \\approx 3.5\\times10^{12} \\quad\\text{and}\\quad 62^{8} \\approx 2.2\\times10^{14}",caption:"7 characters already covers trillions of URLs; we use 7."}]},{id:"high-level-architecture",title:"High-Level Architecture",blocks:[{type:"mermaid",caption:"Write path (create) and read path (redirect).",definition:`flowchart TD
  U["User"] -->|POST /shorten| API["API Service"]
  API --> KGS["Key Generation / Encoder"]
  API --> DB[("Key-Value Store")]
  U2["Browser"] -->|GET /aZ9kQ| API2["Redirect Service"]
  API2 --> Cache[("Redis cache")]
  Cache -->|miss| DB
  API2 -->|301 Location| U2`},{type:"architectureCard",title:"Redis cache in front of the store",description:"Because reads dominate 100:1, an LRU cache of the hottest links absorbs the vast majority of redirects, keeping the database load and latency low.",icon:"database",tags:["cache","LRU","read-heavy"]},{type:"bestPractices",title:"Caching strategy for the redirect path",practices:["**Cache-aside**: on a redirect, check Redis first; on a miss, read the DB and populate the cache.","**LRU eviction** with a TTL (e.g. 24h + jitter) so the hottest links stay resident and memory stays bounded.","**Invalidate on write**: a delete or update to a short URL evicts (or overwrites) its cache entry immediately so stale redirects are never served.","**Warm popular keys** proactively if a link is expected to go viral (e.g. shared by a large account) to avoid a thundering-herd cache miss."]}]},{id:"api-design",title:"API Design",blocks:[{type:"apiTable",endpoints:[{method:"POST",path:"/api/v1/urls",description:"Create a short URL",auth:!0},{method:"GET",path:"/{shortCode}",description:"Redirect to the original URL"},{method:"GET",path:"/api/v1/urls/{shortCode}/stats",description:"Click analytics",auth:!0},{method:"DELETE",path:"/api/v1/urls/{shortCode}",description:"Delete a short URL",auth:!0}]},{type:"code",language:"json",filename:"create-request.json",code:`{
  "longUrl": "https://example.com/some/very/long/path?with=params",
  "customAlias": null,
  "expiresAt": "2027-01-01T00:00:00Z"
}`}]},{id:"database-design",title:"Database Design",blocks:[{type:"code",language:"sql",filename:"schema.sql",highlightLines:[2,3],code:`CREATE TABLE urls (
  short_code   VARCHAR(8) PRIMARY KEY,   -- the Base62 key
  long_url     TEXT NOT NULL,
  created_at   TIMESTAMPTZ DEFAULT now(),
  expires_at   TIMESTAMPTZ,
  click_count  BIGINT DEFAULT 0
);
CREATE INDEX idx_urls_expires_at ON urls (expires_at);`},{type:"callout",variant:"tip",title:"Why a KV store works well",body:"The access pattern is a pure point lookup by primary key. A key-value store (DynamoDB, Cassandra) or even a well-indexed relational table scales this trivially via sharding on `short_code`."}]},{id:"caching-strategy",title:"Key Generation & Encoding",blocks:[{type:"markdown",value:"There are two main approaches. **(A) Hash the URL** (e.g. MD5) and take the first few characters \u2014 simple but must handle collisions. **(B) Use a global counter / unique ID** and Base62-encode it \u2014 collision-free by construction. Approach B (often with a pre-generated **Key Generation Service** or Snowflake-style IDs) is preferred at scale."},{type:"code",language:"java",filename:"Base62.java",highlightLines:[4,14],code:`public final class Base62 {
  private static final String ALPHABET =
      "0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ";
  private static final int BASE = ALPHABET.length(); // 62

  public static String encode(long id) {
    StringBuilder sb = new StringBuilder();
    do {
      sb.append(ALPHABET.charAt((int) (id % BASE)));
      id /= BASE;
    } while (id > 0);
    return sb.reverse().toString();
  }

  public static long decode(String code) {
    long id = 0;
    for (char c : code.toCharArray()) {
      id = id * BASE + ALPHABET.indexOf(c);
    }
    return id;
  }
}`},{type:"code",language:"python",filename:"base62.py",code:`ALPHABET = "0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ"

def encode(num: int) -> str:
    if num == 0:
        return ALPHABET[0]
    chars = []
    while num > 0:
        num, rem = divmod(num, 62)
        chars.append(ALPHABET[rem])
    return "".join(reversed(chars))`},{type:"prosCons",title:"Hashing vs. counter-based IDs",pros:["Counter + Base62: guaranteed unique, no collision checks.","Same long URL can map to the same key if desired."],cons:["Sequential counters are guessable \u2014 add randomness or a KGS pool.","A single global counter is a bottleneck \u2192 use ranges per server."]},{type:"markdown",value:"Three concrete strategies come up in interviews. Compare them directly:"},{type:"table",caption:"Key-generation strategies compared.",headers:["Strategy","How it works","Pros","Cons"],rows:[["Hash + truncate (MD5/SHA-256, first 7 chars)","Hash the long URL, Base62-encode a prefix of the digest.","Deterministic \u2014 same URL always yields the same code, trivial dedup.","Truncated hashes collide; needs a collision-check-and-retry loop on write."],["Global counter + Base62","An auto-incrementing ID (DB sequence or Redis `INCR`) is Base62-encoded.","Zero collisions by construction; simple to reason about.","Sequential \u2192 guessable/enumerable; a single counter is a write bottleneck at scale."],["Snowflake-style distributed ID","64-bit ID packs a timestamp + machine/shard ID + local sequence, generated independently per node.","No central bottleneck, roughly time-sortable, scales horizontally with more nodes.","IDs are longer once Base62-encoded (~9-11 chars) unless you accept a shorter custom bit layout."]]},{type:"callout",variant:"info",title:"What most interviewers want to hear",body:"Lead with **counter + Base62** for its simplicity and zero-collision guarantee, mention the **single-counter bottleneck**, then fix it with either **pre-allocated ID ranges per server** (a lightweight Key Generation Service) or **Snowflake IDs** for a fully distributed, coordination-free generator. Bringing up all three and picking one with a stated reason is stronger than silently defaulting to one."}]},{id:"scaling-strategy",title:"Scaling Strategy",blocks:[{type:"bestPractices",practices:["Put a **CDN / cache** in front so popular links redirect from the edge.","Shard the datastore by `short_code` hash.","Use a **Key Generation Service** that hands out pre-computed key ranges to avoid counter contention.","Batch analytics: increment click counts asynchronously via a queue, not on the redirect hot path.","Prefer **301 (permanent)** for cacheability, or **302** if you need to count every click."]},{type:"callout",variant:"warning",title:"301 vs 302 trade-off",body:"A 301 lets browsers and CDNs cache the redirect (fast, but you lose per-click analytics). A 302 forces a round-trip every time (accurate analytics, more load). Pick based on whether analytics or latency matters more."}]},{id:"trade-offs",title:"Trade-offs",blocks:[{type:"table",headers:["Decision","Gain","Cost"],rows:[["Counter + Base62 keys","No collisions","Guessable unless randomized"],["Cache-aside Redis","Fast redirects","Cache invalidation on delete/expiry"],["301 redirects","CDN cacheable","Inaccurate click counts"],["Async analytics","Fast hot path","Eventually-consistent counts"]]}]},{id:"interview-questions",title:"Interview Questions",blocks:[{type:"interviewQa",items:[{question:"How do you guarantee short codes are unique?",answer:"Use a monotonic unique ID (global counter with per-node ranges, or Snowflake IDs) and Base62-encode it. Uniqueness is guaranteed by construction, so no collision check is needed."},{question:"How do you make keys non-sequential / non-guessable?",answer:"Either pre-generate a shuffled pool of keys in a Key Generation Service, or XOR/scramble the counter with a secret, or include random bits. This prevents enumeration of others' links."},{question:"How do you handle the same long URL submitted twice?",answer:"Optionally store a reverse index (hash of long URL \u2192 short code) and return the existing code. This is a product decision; many shorteners intentionally create a fresh code per request for analytics."},{question:"Why is this system so much more read-heavy than write-heavy, and how does that shape the design?",answer:"Every URL is created once but clicked many times over its life \u2014 a 100:1 (or higher) read:write ratio is typical. This pushes every design decision toward optimizing the **redirect path**: an LRU cache absorbs most reads, 301s let CDNs/browsers cache further, and analytics are moved off the hot path entirely. The write path (create) can afford to be comparatively expensive since it happens rarely."},{question:"How would you shard the database as it grows?",answer:"Shard by a hash of `short_code` (consistent hashing) so lookups stay O(1) \u2014 a request for `/aZ9kQ` hashes straight to its shard without a directory lookup. If key generation uses per-shard counter ranges, the shard can even be encoded implicitly in the key, avoiding a separate routing table."},{question:"What happens if two requests try to create the same custom alias at the same time?",answer:'Enforce uniqueness with a database constraint (`UNIQUE` on `short_code`) and let the second `INSERT` fail, returning a 409 Conflict to the client. Relying on a "check-then-insert" without the constraint is a race condition \u2014 the constraint is the real source of truth, not an application-level check.'},{question:"How do you avoid a hot cache-miss storm on a viral link right after creation?",answer:"On write, proactively populate the cache (write-through) instead of waiting for the first read to miss. For links expected to spike (e.g. shared by a large account), pre-warm the cache. This trades a slightly slower write for protecting the database from a burst of concurrent misses on the same key."},{question:"How would you support link expiration efficiently, at scale?",answer:"Store `expires_at` and check it on read (cheap, no background job needed) rather than a cron sweep for most cases. For reclaiming storage/keys at scale, run a low-priority batch job that deletes expired rows and evicts the corresponding cache entries; it does not need to be real-time."},{question:"Is strong consistency required anywhere in this system?",answer:"Not on the read path \u2014 a slightly stale cached redirect is harmless. The one place consistency matters is **key uniqueness on write**: two creates must never be assigned the same code. A DB `UNIQUE` constraint (or a coordination-free scheme like Snowflake IDs) gives that guarantee without needing distributed locks."}]}]},{id:"references",title:"References",blocks:[{type:"references",items:[{label:"System Design Primer",url:"https://github.com/donnemartin/system-design-primer",source:"GitHub"},{label:"Snowflake ID generation",url:"https://en.wikipedia.org/wiki/Snowflake_ID",source:"Wikipedia"}]}]},{id:"summary",title:"Summary",blocks:[{type:"callout",variant:"summary",body:"Generate unique IDs and **Base62-encode** them for short, collision-free keys. Optimize the **read path** with caching/CDN since redirects dominate 100:1. Keep analytics off the hot path with async counting, and choose 301 vs 302 based on caching vs. accuracy."}]}]},i=t;export{i as default};
